INSERT INTO `products` (`product_id`, `type_id`, `name`, `description`, `image_url`, `usage_recommendation`, `is_active`) VALUES
(1, 1, 'GO Energy Isotonic Gel', 'Diseñado para entregar un suministro rápido y conveniente de carbohidratos de fácil digestión sin necesidad de agua. Primer gel isotónico del mundo.', '1.png', 'Consumir antes o durante ejercicio prolongado. No requiere agua.', 1),
(2, 2, 'GO Energy + Caffeine Gel', 'Proporciona carbohidratos de rápida absorción junto con cafeína para enfoque físico y mental.', '2.png', 'Ideal para competencias de alta intensidad cuando se necesita un impulso extra.', 1),
(3, 3, 'GO Energy + Electrolyte Gel', 'Proporciona 22g de carbohidratos más electrolitos (118mg sodio, 8.5mg potasio, 1.5mg magnesio) por gel.', '3.png', 'Ideal durante ejercicio cuando la pérdida de sodio es alta.', 1),
(4, 4, 'BETA Fuel Dual Source Energy Gel', 'Contiene 40g de carbohidratos en ratio 1:0.8 maltodextrina:fructosa para máximo rendimiento.', '4.png', 'Para eventos de más de 2 horas. Consumir 1-2 geles por hora.', 1),
(5, 5, 'BETA Fuel + Nootropics Gel', 'Combina 40g de carbohidratos con Cognizin® Citicoline para mejorar rendimiento físico y mental.', '5.png', 'Para situaciones que requieren enfoque mental y resistencia física.', 1),
(6, 6, 'GO Energy Bakes', 'Barra horneada con 30g de carbohidratos (10g fructosa) y centro de fruta.', '6.png', 'Consumir durante ejercicios de larga duración (60-90g carbohidratos/hora).', 1),
(7, 7, 'GO Energy Bars', 'Barra nutritiva hecha de frutas y dátiles con 25g de carbohidratos por barra.', '7.png', 'Para días de entrenamiento duro o día previo a competencia.', 1),
(8, 8, 'GO Electrolyte Powder', 'Mezcla de carbohidratos (36g) y electrolitos (sodio) para hidratación óptima.', '8.png', 'Mezclar con 500ml agua. Usar antes o durante ejercicio.', 1),
(9, 9, 'HYDRO Tablet', 'Tableta efervescente alta en sodio para hidratación sin calorías.', '9.png', 'Disolver en 500ml agua. Usar cuando se necesita hidratación sin calorías.', 1),
(10, 10, 'HYDRO + Caffeine Tablet', 'Tableta efervescente con 75mg cafeína para hidratación con impulso energético.', '10.png', 'Para hidratación con beneficio de cafeína.', 1),
(11, 11, 'REGO Rapid Recovery', 'Polvo con 20g proteína de suero y 22g carbohidratos para recuperación post-ejercicio.', '11.png', 'Consumir inmediatamente después del ejercicio.', 1),
(12, 12, 'REGO Rapid Recovery+', 'Versión avanzada con 24g proteína, 38g carbohidratos, BCAAs y L-Glutamina.', '12.png', 'Para sesiones intensas o prolongadas.', 1),
(13, 13, 'SiS Protein Bars', 'Barra de proteína (20g por paquete) cubierta de chocolate.', '13.png', 'Para crecimiento y recuperación muscular.', 1),
(14, 14, 'BCAA Tablets', '4g de aminoácidos ramificados en ratio 2:1:1 (Leucina, Isoleucina, Valina).', '14.png', 'Tomar antes, durante o después del entrenamiento.', 1),
(15, 15, 'Daily Multivitamins', 'Contiene 7 vitaminas esenciales (A, D, E, C, Tiamina, Riboflavina, Niacina).', '15.png', 'Una tableta diaria para apoyo nutricional.', 1),
(16, 16, 'IMMUNE Tablet', 'Tableta efervescente con 200mg Vitamina C y 2.5mg Hierro para apoyo inmunológico.', '16.png', 'Disolver en agua. Usar antes/durante/después del ejercicio.', 1),
(17, 4, 'BETA FUEL 80 Dual Source Energy Drink', 'Polvo energético con 80g de carbohidratos en ratio 1:0.8 maltodextrina:fructosa. Favorecido por atletas de élite para eventos de más de 2 horas.', '17.png', 'Mezclar con agua. Consumir 80-120g de carbohidratos por hora durante eventos de resistencia.', 1),
(18, 4, 'BETA FUEL ENERGY CHEWS', 'Gomitas energéticas con 48g de carbohidratos por paquete (7g por gomita). Formato fácil de consumir durante ejercicio.', '18.png', 'Consumir 1-3 gomitas cada hora durante ejercicio para alcanzar 80-120g de carbohidratos por hora.', 1),
(19, 1, 'GO Energy Isotonic Gel Lemon-Lime', 'Gel isotónico con 22g de carbohidratos y formulación rápida de absorber. Sabor limón-lima.', '19.png', 'Consumir antes o durante ejercicio prolongado para mantener niveles de energía.', 1),
(20, 1, 'GO Energy Isotonic Gel Berry Mix', 'Gel energético isotónico sabor frutos rojos con carbohidratos de digestión rápida.', '20.png', 'Ideal para uso durante entrenamientos intensos sin necesidad de agua.', 1),
(21, 2, 'GO Energy + Caffeine Gel Double Espresso', 'Gel con 22g carbohidratos y 100mg cafeína para un impulso energético máximo.', '21.png', 'Usar en tramos finales de carreras o esfuerzos de alta intensidad.', 1),
(22, 2, 'GO Energy + Caffeine Gel Cola', 'Gel energético con 22g carbohidratos y 75mg cafeína. Sabor cola.', '22.png', 'Para mantener alerta mental durante sesiones prolongadas.', 1),
(23, 3, 'GO Energy + Electrolyte Gel Citrus', 'Gel con carbohidratos y electrolitos esenciales para reponer sales minerales.', '23.png', 'Perfecto cuando la sudoración es elevada.', 1),
(24, 3, 'GO Energy + Electrolyte Gel Pineapple', '22g carbohidratos más mezcla equilibrada de electrolitos. Sabor piña.', '24.png', 'Para actividades de larga duración bajo calor.', 1),
(25, 4, 'BETA Fuel 40g Gel Orange', 'Gel de doble fuente con 40g carbohidratos en ratio 1:0.8. Sabor naranja.', '25.png', 'Para mantener máximo rendimiento en esfuerzos prolongados.', 1),
(26, 4, 'BETA Fuel 40g Gel Strawberry', 'Gel especializado para resistencia de larga duración con absorción mejorada.', '26.png', 'Consumir 1-2 geles por hora en eventos >2h.', 1),
(27, 5, 'BETA Fuel + Nootropics Gel Raspberry', '40g carbohidratos + citicolina para mejorar enfoque. Sabor frambuesa.', '27.png', 'Para momentos críticos de concentración en competencia.', 1),
(28, 5, 'BETA Fuel + Nootropics Gel Mango', 'Gel avanzado de rendimiento y claridad mental.', '28.png', 'Usar cuando se requiere concentración y potencia sostenida.', 1),
(29, 6, 'GO Energy Bakes Apple Cinnamon', 'Bocadillo horneado con 30g carbohidratos y centro de manzana.', '29.png', 'Para mantener energía en sesiones largas.', 1),
(30, 6, 'GO Energy Bakes Blueberry', 'Barra horneada con centro de arándanos y fructosa.', '30.png', 'Consumir durante esfuerzos prolongados.', 1),
(31, 7, 'GO Energy Bar Chocolate & Orange', 'Barra nutritiva con fruta y dátiles. 25g carbohidratos.', '31.png', 'Para carga energética antes de entrenamientos duros.', 1),
(32, 7, 'GO Energy Bar Banana Fudge', 'Barra energética de banana con carbohidratos de rápida disponibilidad.', '32.png', 'Perfecta para pre-entrenamiento o recuperación.', 1),
(33, 8, 'GO Electrolyte Powder Tropical', 'Polvo con 36g carbohidratos y sodio para hidratación y energía.', '33.png', 'Mezclar con 500ml agua para uso durante ejercicio.', 1),
(34, 8, 'GO Electrolyte Powder Red Berry', 'Bebida isotónica diseñada para reponer sales minerales.', '34.png', 'Usar en ambientes calurosos.', 1),
(35, 9, 'HYDRO Tablet Lemon', 'Tableta efervescente con alto contenido en sodio. Sabor limón.', '35.png', 'Ideal para mantener hidratación diaria sin calorías.', 1),
(36, 9, 'HYDRO Tablet Berry', 'Hidratación sin calorías formulada para entrenamientos ligeros.', '36.png', 'Disolver en agua antes o después de entrenar.', 1),
(37, 10, 'HYDRO + Caffeine Tablet Citrus', 'Tableta de hidratación con 75mg cafeína. Sabor cítrico.', '37.png', 'Perfecta para deportes de resistencia con necesidad de alerta.', 1),
(38, 10, 'HYDRO + Caffeine Tablet Peach', 'Hidratación avanzada con cafeína y sodio.', '38.png', 'Usar en carreras intensas o entrenamientos largos.', 1),
(39, 11, 'REGO Rapid Recovery Chocolate Orange', 'Mezcla para recuperación con proteína y carbohidratos. Sabor chocolate-naranja.', '39.png', 'Tomar inmediatamente post-entreno.', 1),
(40, 11, 'REGO Rapid Recovery Strawberry Cream', 'Recuperación muscular rápida con ingredientes premium.', '40.png', 'Usar tras sesiones de fuerza o cardio intenso.', 1),
(41, 12, 'REGO Rapid Recovery+ Vanilla', 'Versión avanzada con BCAAs y glutamina. Sabor vainilla.', '41.png', 'Para atletas con alta carga de entrenamiento.', 1),
(42, 12, 'REGO Rapid Recovery+ Chocolate Mint', 'Fórmula de recuperación avanzada. Sabor chocolate-menta.', '42.png', 'Consumir tras entrenamientos largos.', 1),
